// Calculate all weekly metrics from the full alert log
// Filter to past 7 days, then compute summary statistics

const allAlerts = $input.all().map(i => i.json);
const now = new Date();
const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

// Filter to past 7 days
const weekAlerts = allAlerts.filter(a => {
  const ingested = new Date(a.ingested_at);
  return ingested >= sevenDaysAgo;
});

if (weekAlerts.length === 0) {
  return [{ json: { _no_data: true, week_start: sevenDaysAgo.toISOString().split('T')[0] } }];
}

// ── Core counts ────────────────────────────────────────────────
const total = weekAlerts.length;
const scored = weekAlerts.filter(a => a.scored_at);
const truePositives = scored.filter(a => a.triage_decision === 'true_positive');
const falsePositives = scored.filter(a => a.triage_decision === 'false_positive');
const needsInvestigation = scored.filter(a => a.triage_decision === 'needs_investigation');

// ── Severity breakdown ─────────────────────────────────────────
const bySeverity = { critical: 0, high: 0, medium: 0, low: 0, info: 0 };
weekAlerts.forEach(a => {
  const sev = (a.severity || 'low').toLowerCase();
  if (bySeverity.hasOwnProperty(sev)) bySeverity[sev]++;
});

// ── Mean time to triage (minutes) ─────────────────────────────
const triageTimesMinutes = scored
  .filter(a => a.ingested_at && a.scored_at)
  .map(a => {
    const ingest = new Date(a.ingested_at).getTime();
    const score  = new Date(a.scored_at).getTime();
    return (score - ingest) / 60000;
  })
  .filter(t => t >= 0 && t < 1440); // sanity filter: 0–24 hours

const mttt = triageTimesMinutes.length > 0
  ? (triageTimesMinutes.reduce((a, b) => a + b, 0) / triageTimesMinutes.length).toFixed(1)
  : 'N/A';

// ── Top 3 recurring findings ───────────────────────────────────
const titleCounts = {};
weekAlerts.forEach(a => {
  if (a.title) {
    titleCounts[a.title] = (titleCounts[a.title] || 0) + 1;
  }
});

const topFindings = Object.entries(titleCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([title, count], i) => ({ rank: i + 1, title, count }));

// ── Open tickets ───────────────────────────────────────────────
const openTickets   = weekAlerts.filter(a => a.jira_status === 'open').length;
const closedTickets = weekAlerts.filter(a => a.jira_status === 'closed').length;

// ── True positive rate ─────────────────────────────────────────
const tpRate = scored.length > 0
  ? Math.round((truePositives.length / scored.length) * 100)
  : 0;

// ── Week label ─────────────────────────────────────────────────
const weekLabel = sevenDaysAgo.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' });
const todayLabel = now.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' });

const metrics = {
  week_label:         `${weekLabel} — ${todayLabel}`,
  total_alerts:       total,
  scored_alerts:      scored.length,
  true_positives:     truePositives.length,
  false_positives:    falsePositives.length,
  needs_investigation: needsInvestigation.length,
  tp_rate_pct:        tpRate,
  mttt_minutes:       mttt,
  severity_critical:  bySeverity.critical,
  severity_high:      bySeverity.high,
  severity_medium:    bySeverity.medium,
  severity_low:       bySeverity.low,
  open_tickets:       openTickets,
  closed_tickets:     closedTickets,
  top_finding_1:      topFindings[0] ? `${topFindings[0].title} (${topFindings[0].count})` : '—',
  top_finding_2:      topFindings[1] ? `${topFindings[1].title} (${topFindings[1].count})` : '—',
  top_finding_3:      topFindings[2] ? `${topFindings[2].title} (${topFindings[2].count})` : '—',
  generated_at:       now.toISOString()
};

return [{ json: metrics }];

